import React, {useState, useEffect} from 'react';
import './App.css';
import './ProjectPage.css';
import transition from './transition.js';
import NavBar from './NavBar';
import Footer from './Footer';

import ProjectTitles from './components/projectPage/ProjectTitles';
import MetaList from './components/projectPage/MetaList';

import Cont_Clock from './projectContent/Cont_Clock';
import Cont_Footwork from './projectContent/Cont_Footwork';


import thumb from './img/thumb.jpg';

const projectDict = {
  "clock": {
    "title": "Clock",
    "subtitle": "This is the clk subtitle",
    "metaLists": [
      { "title":"SKILLS",
        "items":["3dp","rhino","item3"],
      },
      { "title":"TOOLS",
        "items":["arduino","item2","item3"],
      },
    ],
    "content": <Cont_Clock></Cont_Clock>,
  },  

  "footwork": {
    "title": "Footwork XVII",
    "subtitle": "This is the fw subtitle",
    "metaLists": [
      { "title":"SKILLS",
        "items":["gd","3d","pub"],
      },
      { "title":"TOOLS",
        "items":["blender","item2","item3"],
      },
    ],
    "content": <Cont_Footwork></Cont_Footwork>,
  },
}

const projComponentDict = {
  "footwork": [<Cont_Footwork />, "Footwork XVII"],
  "clock": [<Cont_Clock />, "Sequencer Clock"],
}


function ProjectPage({projectKey}) {
    // useEffect(() => {
    //     document.title = projComponentDict[projectKey][1]
    // },[])

    const projComponent = projComponentDict[projectKey]


  return (
    <div>
      <NavBar></NavBar>

      {projComponent ? (
          projComponent     
      ) : ( <></>)}


      <Footer></Footer>
    </div>
  );
}

export default transition(ProjectPage);
